CREATE TABLE "ExpenseCategory" ("id" TEXT NOT NULL,"name" TEXT NOT NULL,"code" TEXT,"parentId" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "ExpenseCategory_pkey" PRIMARY KEY("id"));
CREATE TABLE "Expense" ("id" TEXT NOT NULL,"reference" TEXT NOT NULL,"location" TEXT NOT NULL,"categoryId" TEXT NOT NULL,"subCategoryId" TEXT,"expenseDate" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"expenseFor" TEXT NOT NULL,"contact" TEXT,"applicableTax" TEXT,"total" DECIMAL(12,2) NOT NULL,"note" TEXT,"attachmentName" TEXT,"isRecurring" BOOLEAN NOT NULL DEFAULT false,"recurrenceEvery" INTEGER,"recurrenceUnit" TEXT,"occurrences" INTEGER,"paymentAmount" DECIMAL(12,2) NOT NULL DEFAULT 0,"paymentDate" TIMESTAMP(3),"paymentMethod" TEXT,"paymentAccount" TEXT,"paymentNote" TEXT,"addedBy" TEXT NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "Expense_pkey" PRIMARY KEY("id"));
CREATE UNIQUE INDEX "ExpenseCategory_name_parentId_key" ON "ExpenseCategory"("name","parentId");CREATE UNIQUE INDEX "Expense_reference_key" ON "Expense"("reference");CREATE INDEX "Expense_expenseDate_idx" ON "Expense"("expenseDate");CREATE INDEX "Expense_categoryId_idx" ON "Expense"("categoryId");
ALTER TABLE "ExpenseCategory" ADD CONSTRAINT "ExpenseCategory_parentId_fkey" FOREIGN KEY("parentId") REFERENCES "ExpenseCategory"("id") ON DELETE SET NULL ON UPDATE CASCADE;
ALTER TABLE "Expense" ADD CONSTRAINT "Expense_categoryId_fkey" FOREIGN KEY("categoryId") REFERENCES "ExpenseCategory"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "Expense" ADD CONSTRAINT "Expense_subCategoryId_fkey" FOREIGN KEY("subCategoryId") REFERENCES "ExpenseCategory"("id") ON DELETE SET NULL ON UPDATE CASCADE;
